module top_module(
	input clk,
	input up_down,
	input clear,
	output reg [3:0] count);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (clear)
		count <= 0;
	else if (up_down)
		count <= count + 1;
	else
		count <= count - 1;
end

endmodule
